query VideoPageInRealmQuery(
  $id: ID!
  $realmPath: String!
  $listId: ID!
  $eventUser: String
  $eventPassword: String
) {
  ...UserData
  event: eventById(id: $id) {
    __typename
    ...VideoPageEventData_3J3oez
    ... on AuthorizedEvent {
      isReferencedByRealm(path: $realmPath)
    }
    ... on Node {
      __isNode: __typename
      id
    }
  }
  realm: realmByPath(path: $realmPath) {
    ...VideoPageRealmData
    ...NavigationData
    id
  }
  playlist: playlistById(id: $listId) {
    __typename
    ...PlaylistBlockPlaylistData
    ... on Node {
      __isNode: __typename
      id
    }
  }
}

fragment NavigationData on Realm {
  id
  name
  path
  nav {
    header {
      name
      path
    }
    list {
      name
      path
      hasChildren
    }
    listOrder
  }
}

fragment PlaylistBlockPlaylistData on Playlist {
  __isPlaylist: __typename
  __typename
  ... on NotAllowed {
    dummy
  }
  ... on AuthorizedPlaylist {
    id
    title
    description
    creator
    canWrite
    entries {
      __typename
      ... on AuthorizedEvent {
        id
        ...VideoListEventData
      }
      ... on Missing {
        dummy
      }
      ... on NotAllowed {
        dummy
      }
      ... on Node {
        __isNode: __typename
        id
      }
    }
  }
}

fragment SeriesBlockSeriesData on Series {
  id
  title
  created
  description
  state
  metadata
  canWrite
  entries {
    __typename
    ... on AuthorizedEvent {
      id
      ...VideoListEventData
    }
    ... on NotAllowed {
      dummy
    }
    ... on Node {
      __isNode: __typename
      id
    }
  }
}

fragment UserData on Query {
  currentUser {
    username
    displayName
    userRealmHandle
    canUpload
    canUseStudio
    canUseEditor
    canCreateUserRealm
    canCreateSeries
    canCreatePlaylists
    isTobiraAdmin
    canFindUnlisted
    roles
    userRole
  }
}

fragment VideoListEventData on AuthorizedEvent {
  id
  title
  created
  creators
  isLive
  description
  series {
    title
    id
  }
  syncedData {
    thumbnail
    duration
    startTime
    endTime
    audioOnly
  }
}

fragment VideoPageAuthorizedData_3J3oez on AuthorizedEvent {
  authorizedData(user: $eventUser, password: $eventPassword) {
    tracks {
      uri
      flavor
      mimetype
      resolution
      isMaster
    }
    captions {
      uri
      lang
    }
    segments {
      uri
      startTime
    }
  }
  id
}

fragment VideoPageEventData_3J3oez on Event {
  __isEvent: __typename
  __typename
  ... on NotAllowed {
    dummy
  }
  ... on AuthorizedEvent {
    id
    title
    description
    creators
    created
    isLive
    opencastId
    metadata
    canWrite
    hasPassword
    syncedData {
      updated
      duration
      startTime
      endTime
      thumbnail
    }
    ...VideoPageAuthorizedData_3J3oez
    series {
      id
      opencastId
      title
      ...SeriesBlockSeriesData
    }
  }
}

fragment VideoPageRealmData on Realm {
  name
  path
  isMainRoot
  ancestors {
    name
    path
    id
  }
}
